import{c as a,Q as o,j as n,m as s}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"刷怪机制:mobcap、光照条件与 ticking 耦合","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/15-刷怪机制-mobcap光照条件与ticking耦合.md","filePath":"minecraftLearning/15-刷怪机制-mobcap光照条件与ticking耦合.md","lastUpdated":1781677803000}'),r={name:"minecraftLearning/15-刷怪机制-mobcap光照条件与ticking耦合.md"};function e(i,t,p,l,d,c){return o(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="刷怪机制-mobcap、光照条件与-ticking-耦合" tabindex="-1">刷怪机制:mobcap、光照条件与 ticking 耦合 <a class="header-anchor" href="#刷怪机制-mobcap、光照条件与-ticking-耦合" aria-label="Permalink to &quot;刷怪机制:mobcap、光照条件与 ticking 耦合&quot;">​</a></h1><p>你在地下挖矿,周围不停冒僵尸;你在地表造了个刷怪塔,挂机就能堆一仓库的火药。这两件事背后是同一套&quot;自然刷怪&quot;逻辑。它不是&quot;地图上随机撒怪&quot;那么简单,而是一条<strong>每 tick 都在跑、被一堆配额和条件层层卡住</strong>的流水线。理解它,你才会明白为什么&quot;照亮&quot;能防怪、为什么刷怪塔要把人挂在 128 格外、为什么有的农场效率忽高忽低。</p><blockquote><p>一句话先记住:<strong>刷怪是&quot;在 ticking 区块里,按类别配额(mobcap)反复掷骰子找合法落点&quot;的过程——配额没满才尝试,落点要同时过方块、光照、距离三道关。</strong> 你能影响刷怪,本质就是在操纵这三道关和那个配额。</p></blockquote><hr><h2 id="一、整体循环-每-tick-一轮-但被配额掐住" tabindex="-1">一、整体循环:每 tick 一轮,但被配额掐住 <a class="header-anchor" href="#一、整体循环-每-tick-一轮-但被配额掐住" aria-label="Permalink to &quot;一、整体循环:每 tick 一轮,但被配额掐住&quot;">​</a></h2><p>服务端每个游戏 tick,会对<strong>正在 ticking 的区块</strong>(就是第 05 篇讲的进入模拟距离、达到 ticking 等级的那些)跑一轮刷怪尝试。关键是它不是无脑刷:</p><ol><li>先统计<strong>当前世界里每个类别已有多少只</strong>。</li><li>拿这个数和该类别的 **mobcap(数量上限)**比。</li><li><strong>没到上限才进入刷怪流程</strong>;到了就这个类别这轮直接跳过。</li></ol><p>所以刷怪的第一道闸门不是&quot;哪里能刷&quot;,而是&quot;<strong>还允许刷吗</strong>&quot;。这也是所有刷怪农场的第一性原理:<strong>想让目标怪刷得快,先把 mobcap 腾出来给它</strong>。</p><hr><h2 id="二、mobcap-配额怎么算" tabindex="-1">二、mobcap:配额怎么算 <a class="header-anchor" href="#二、mobcap-配额怎么算" aria-label="Permalink to &quot;二、mobcap:配额怎么算&quot;">​</a></h2><p>怪物按**类别(category)**分桶,各算各的上限。常见类别:</p><table tabindex="0"><thead><tr><th>类别</th><th>典型成员</th><th>大致基准 cap</th></tr></thead><tbody><tr><td>monster(敌对)</td><td>僵尸、骷髅、苦力怕、蜘蛛</td><td>70</td></tr><tr><td>creature(友好动物)</td><td>牛、羊、猪、鸡</td><td>10</td></tr><tr><td>ambient(环境)</td><td>蝙蝠</td><td>15</td></tr><tr><td>water_creature</td><td>鱿鱼</td><td>5</td></tr><tr><td>water_ambient</td><td>鳕鱼、鲑鱼等鱼群</td><td>20</td></tr><tr><td>underground_water</td><td>发光鱿鱼</td><td>5</td></tr><tr><td>axolotls</td><td>美西螈</td><td>5</td></tr></tbody></table><p>但这些数字<strong>不是全图固定值</strong>,而是按&quot;<strong>可刷怪区块数</strong>&quot;缩放的:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>该类别 cap ≈ 基准值 × (当前可刷怪区块数 / 289)</span></span></code></pre></div><p>那个 289 = 17×17,来自&quot;以每个玩家为中心的一块刷怪方阵&quot;。要点有两个:</p><ul><li><strong>cap 是按玩家、按加载量动态算的,不是死的 70。</strong> 加载的区块越多、玩家越多,总配额越大。</li><li><strong>多个玩家如果共享重叠的加载区域,可刷怪区块会被去重</strong>,不会简单翻倍——这正是单人多账号挂机刷怪场要算计的地方。</li></ul><blockquote><p>反直觉点:<strong>清掉远处洞穴里那些你根本看不见的怪,能直接提升你脚下农场的刷新速度。</strong> 因为它们和你的目标怪争同一个 monster cap。很多&quot;农场效率忽高忽低&quot;就是因为周围天然洞穴在偷配额。</p></blockquote><hr><h2 id="三、找落点-三道关" tabindex="-1">三、找落点:三道关 <a class="header-anchor" href="#三、找落点-三道关" aria-label="Permalink to &quot;三、找落点:三道关&quot;">​</a></h2><p>配额允许后,才开始为这一类挑具体位置。流程大致是:在每个候选区块里随机选一列 (x, z)、随机一个 y,然后对这个点做检查。通过了还会<strong>就地成群(pack spawn)</strong> 刷一小群(通常 1–4 只,狼、僵尸猪灵等可能成群更大),而不是一只一只地刷。</p><p>落点要同时过三关:</p><h3 id="关一-方块-空间条件" tabindex="-1">关一:方块/空间条件 <a class="header-anchor" href="#关一-方块-空间条件" aria-label="Permalink to &quot;关一:方块/空间条件&quot;">​</a></h3><ul><li>脚下得是<strong>实心、能站住</strong>的方块(具体看怪的 <code>SpawnPlacements</code> 规则,有的要求草方块、有的要求特定方块)。</li><li>上方要有<strong>足够空间</strong>容纳这只怪(高个子的怪需要更高净空)。</li><li>落点本身不能是固体、不能卡在墙里、通常不能在含水方块里(水生怪相反)。</li></ul><h3 id="关二-光照条件-1-18-是个分水岭" tabindex="-1">关二:光照条件(1.18 是个分水岭) <a class="header-anchor" href="#关二-光照条件-1-18-是个分水岭" aria-label="Permalink to &quot;关二:光照条件(1.18 是个分水岭)&quot;">​</a></h3><p>这是最常被讲错的一关。<strong>1.18 之后</strong>:</p><ul><li>敌对怪(monster)是否能刷,<strong>只看方块光(block light)</strong>,要求 <strong>blockLight = 0</strong>。</li><li><strong>天空光(sky light)不再参与敌对刷怪判定</strong>。</li></ul><p>这句话的后果很大:</p><blockquote><p>1.18 之前,白天地表天空光高,怪不刷;晚上天空光降下来,地表才刷怪。<strong>1.18 之后,地表白天不刷怪,不再是因为&quot;天空光高&quot;,而是另有昼夜/亮度的整体抑制逻辑;但单看一个洞口、一个阴影格能不能刷怪,判据已经变成&quot;方块光是不是 0&quot;。</strong></p></blockquote><p>实践上这带来一个清晰结论:<strong>想防怪,只能靠&quot;方块光源&quot;(火把、萤石、海晶灯之类)把 blockLight 抬到 1 以上。</strong> 靠天窗、靠天空光照进来,对挡 1.18+ 的敌对刷怪没用。</p><p>而友好动物(creature)的判定不一样,它们通常要求在<strong>草方块上、且天空光足够亮</strong>——所以牛羊是白天地表成群刷、夜里不刷。<strong>&quot;照亮防怪只对敌对怪有效&quot;</strong> 就是这么来的:两类怪看的根本是不同的光照量。</p><h3 id="关三-与玩家的距离区间" tabindex="-1">关三:与玩家的距离区间 <a class="header-anchor" href="#关三-与玩家的距离区间" aria-label="Permalink to &quot;关三:与玩家的距离区间&quot;">​</a></h3><p>落点离最近玩家的距离要落在一个<strong>环形区间</strong>里,经验值大致是:</p><ul><li><strong>太近(约 24 格内):不刷</strong>——避免怪直接糊脸生成。</li><li><strong>太远(约 128 格外):不参与刷怪 / 立刻消失</strong>——见下一节。</li></ul><p>所以真正能刷怪的是<strong>以玩家为中心、半径 24~128 的一个球壳</strong>。刷怪塔之所以要把&quot;刷怪平台&quot;放在离挂机点 24 格以上、128 格以内,就是为了让平台落在这个壳里,同时把其它一切可刷表面<strong>封死或移出球壳</strong>,逼配额全砸到平台上。</p><hr><h2 id="四、despawn-怪怎么消失" tabindex="-1">四、despawn:怪怎么消失 <a class="header-anchor" href="#四、despawn-怪怎么消失" aria-label="Permalink to &quot;四、despawn:怪怎么消失&quot;">​</a></h2><p>刷出来不等于留得住。怪的消亡也按距离玩家分档:</p><table tabindex="0"><thead><tr><th>离最近玩家距离</th><th>行为</th></tr></thead><tbody><tr><td>&gt; 128 格</td><td><strong>立即消失</strong>(硬性)</td></tr><tr><td>32 ~ 128 格</td><td>每 tick 有概率消失(待得越久越可能)</td></tr><tr><td>&lt; 32 格</td><td>不会自然消失</td></tr></tbody></table><p>外加一个开关:<strong>persistent(持久)</strong> 的怪永不自然消失。让怪变 persistent 的途径包括:被命名牌命名、捡过装备/物品、某些特殊生成(村民、驯服的动物、结构里带的怪等)。</p><blockquote><p>反直觉点:<strong>站在 128 格外,能让某些怪被&quot;清空重刷&quot;。</strong> 因为你一离开 128,旧怪立刻 despawn,配额腾空,等你回来(或在另一个刷怪点)就会刷新一批。一些刷怪场设计会刻意利用&quot;玩家位置切换 → 旧怪集体消失 → cap 重置 → 新怪猛刷&quot;这个节奏。反过来,你想保住一只稀有怪,要么命名它、要么别离开 128 格。</p></blockquote><p>注意 despawn 看的是<strong>离最近玩家的距离</strong>,和刷怪用的是同一套&quot;以玩家为锚&quot;的空间观——整套机制都绕着玩家转,没有玩家在附近的地方既不刷也不消。</p><hr><h2 id="五、和-ticking、随机性、难度的耦合" tabindex="-1">五、和 ticking、随机性、难度的耦合 <a class="header-anchor" href="#五、和-ticking、随机性、难度的耦合" aria-label="Permalink to &quot;五、和 ticking、随机性、难度的耦合&quot;">​</a></h2><p>刷怪不是孤立系统,它和前面几篇讲的东西全咬在一起:</p><ul><li><strong>和 ticking 范围耦合</strong>:只有进入 ticking 等级的区块才跑刷怪循环,可刷怪区块数也决定 mobcap。<strong>离开模拟距离的区域既不刷怪、已有的怪也不 tick</strong>——这就是第 05 篇说的&quot;远处不更新&quot;在刷怪上的体现。这也是挂机刷怪场必须让玩家本人(或区块加载手段)把目标区块钉在 ticking 范围的原因。</li><li><strong>和随机性耦合</strong>:落点是随机选的列、随机的 y,所以刷怪效率天然有方差。把&quot;无效刷怪表面&quot;封掉(铺半砖、点光、灌水、削空间),等于提高每次随机落点命中目标平台的概率——农场优化的本质就是<strong>抬高随机骰子的有效命中率</strong>。</li><li><strong>和区域难度耦合</strong>:玩家在一个区块停留越久(InhabitedTime 累积),局部难度上升,会影响怪的装备、增益等;但它改的是&quot;刷出来的怪多强&quot;,不是&quot;刷不刷得出&quot;。</li></ul><hr><h2 id="六、刷怪笼-另一条不走-mobcap-的路" tabindex="-1">六、刷怪笼:另一条不走 mobcap 的路 <a class="header-anchor" href="#六、刷怪笼-另一条不走-mobcap-的路" aria-label="Permalink to &quot;六、刷怪笼:另一条不走 mobcap 的路&quot;">​</a></h2><p>上面讲的是<strong>自然刷怪</strong>。地牢里的<strong>刷怪笼(spawner)</strong> 是另一套独立逻辑,别混:</p><ul><li>刷怪笼是个方块实体,玩家进入约 16 格内被激活,<strong>周期性在自己周围一小圈尝试生成固定种类的怪</strong>。</li><li>它有自己的<strong>局部上限</strong>(附近同种怪到达约 6 只就停),<strong>不直接吃全局 mobcap 那套 289 缩放</strong>,判据也更局部(看周围一小块体积里的同类数量、光照/空间等)。</li><li>所以&quot;刷怪笼农场&quot;和&quot;天然刷怪塔&quot;是两种完全不同的设计:前者操纵单个笼子的激活与堆叠,后者操纵全局配额与可刷怪表面。</li></ul><hr><h2 id="七、区域难度-刷怪强度怎么随时间变硬" tabindex="-1">七、区域难度:刷怪强度怎么随时间变硬 <a class="header-anchor" href="#七、区域难度-刷怪强度怎么随时间变硬" aria-label="Permalink to &quot;七、区域难度:刷怪强度怎么随时间变硬&quot;">​</a></h2><p>前面所有关卡管的都是&quot;刷不刷、刷多少&quot;,但<strong>刷出来的怪有多难缠</strong>是另一套独立的数值——<strong>区域难度(local difficulty)</strong>。它不改数量,只改质量。</p><p>它不是一个固定值,而是每个位置实时算出来的,综合了四样东西:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>区域难度 ← 世界难度(和平/简单/普通/困难,这是总开关)</span></span>
<span class="line"><span>         + 该 chunk 的 InhabitedTime(玩家在这个区块累计停留的 tick,见第 08 篇 chunk NBT)</span></span>
<span class="line"><span>         + 世界总天数(开局越久,整体越硬)</span></span>
<span class="line"><span>         + 月相(满月偏硬)</span></span></code></pre></div><p>其中最值得说的是 <strong>InhabitedTime</strong>:它就存在每个 chunk 的 NBT 里(第 08 篇那张结构表里出现过),<strong>玩家在某个区块待得越久,这个值涨得越高,局部难度越高</strong>。</p><p>难度抬上去,影响的全是&quot;怪的强度&quot;,而不是&quot;刷怪的概率&quot;:</p><table tabindex="0"><thead><tr><th>维度</th><th>高区域难度下的表现</th></tr></thead><tbody><tr><td>装备</td><td>僵尸/骷髅更可能带盔甲、武器,甚至带附魔</td></tr><tr><td>增益</td><td>怪身上更可能带药水效果;部分怪刷出时附带额外属性</td></tr><tr><td>援军</td><td>僵尸被打时召唤援军(reinforcement)的概率更高</td></tr><tr><td>特殊化</td><td>苦力怕被雷劈成充能苦力怕、僵尸转化等概率相关项</td></tr></tbody></table><blockquote><p>反直觉点:<strong>一个长期挂机的刷怪场,怪会越来越强。</strong> 因为玩家长时间钉在那片区块,InhabitedTime 不断累积,局部难度爬高,刷出来的怪逐渐开始带甲带附魔。这是设计上的有意取舍——<strong>久居既给你高产(配额、加载),也让你面对的怪更硬</strong>,奖励和惩罚绑在同一个计时器上。想压低它,只能换地方挂机,或本就在低世界难度下玩。</p></blockquote><p>和前面那道配额闸门划清界线:<strong>mobcap 管&quot;刷多少&quot;,区域难度管&quot;刷得多狠&quot;</strong>,两者互不干涉。你把农场效率拉满,只是让一批批怪更快地过来——它们单个有多难打,是 local difficulty 在背后调的另一个旋钮。</p><hr><h2 id="八、串起来-你能拧的几个旋钮" tabindex="-1">八、串起来:你能拧的几个旋钮 <a class="header-anchor" href="#八、串起来-你能拧的几个旋钮" aria-label="Permalink to &quot;八、串起来:你能拧的几个旋钮&quot;">​</a></h2><p>把这套机制反过来看,玩家能影响刷怪的手段其实就那么几个旋钮,全对应上面的关卡:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>想多刷目标怪                想防怪 / 防刷</span></span>
<span class="line"><span>─────────────────          ─────────────────</span></span>
<span class="line"><span>腾空 mobcap(灭掉抢配额的怪)   占满空间(让落点无处可刷)</span></span>
<span class="line"><span>封死其它可刷表面(半砖/光/水)  方块光源抬 blockLight≥1(只对敌对有效)</span></span>
<span class="line"><span>把平台放进 24~128 球壳         整片照亮/铺非法落点方块</span></span>
<span class="line"><span>玩家钉在 ticking 范围内         让区域离开模拟距离</span></span>
<span class="line"><span>利用 128 外 despawn 清场重刷    给稀有怪命名防 despawn</span></span></code></pre></div><p>核心始终是那句话:<strong>刷怪是&quot;配额没满 → 在 24~128 的壳里随机找落点 → 过方块/光照两关 → 成群生成&quot;的循环。</strong> 你做的每一个农场优化、每一次&quot;为什么这里不刷怪&quot;的排查,都能落到&quot;是配额、落点、还是某一道关被卡住了&quot;上。</p>`,64)])])}const h=a(r,[["render",e]]);export{u as __pageData,h as default};
